import{_ as r,C as o,o as a,c as i,a7 as d,E as n}from"./chunks/framework.D3qk93i9.js";const g=JSON.parse('{"title":"Firmware Flashing","description":"Flash OSRBOT firmware in the browser with no-BOOT app update or BOOT factory restore.","frontmatter":{"title":"Firmware Flashing","description":"Flash OSRBOT firmware in the browser with no-BOOT app update or BOOT factory restore."},"headers":[],"relativePath":"en/updater.md","filePath":"en/updater.md","lastUpdated":1781683467000}'),s={name:"en/updater.md"};function l(c,e,p,h,m,f){const t=o("FirmwareUpdater");return a(),i("div",null,[e[0]||(e[0]=d('<h1 id="firmware-flashing" tabindex="-1">Firmware Flashing <a class="header-anchor" href="#firmware-flashing" aria-label="Permalink to &quot;Firmware Flashing&quot;">​</a></h1><blockquote><p>Chrome or Edge is required because this page uses the Web Serial API.</p></blockquote><p>This page provides two flashing paths:</p><ul><li><strong>No-BOOT app update</strong>: the device boots normally and only the app partition is updated. BOOT mode is not required, but the currently running firmware must support the <code>fw</code> update protocol. Remote firmware can be selected from the current repository examples; custom URLs must be full HTTPS addresses.</li><li><strong>Factory restore</strong>: first flash, factory restore, or broken firmware recovery. BOOT download mode is required and the built-in full flash image is written.</li></ul><p>Local <code>.bin</code> files are still supported for internal testing or temporary firmware validation.</p><p>Recommended test after flashing an example firmware:</p><ol><li>Open the serial monitor, send <code>diag</code>, and check SN, flash, heap, I2C, IMU, magnetometer, and SBUS status.</li><li>Send <code>imu</code> and <code>mag</code>, then gently rotate the board and confirm raw data changes.</li><li>Send <code>ledtest</code> and <code>beeptest</code> to verify the LED and buzzer.</li><li>Send <code>rc</code>, move the transmitter sticks, and confirm channel values change.</li><li>Lift the vehicle, then send <code>servo left</code>, <code>servo center</code>, and <code>servo right</code>.</li><li>Lift the vehicle, then send <code>motor fwd</code>, <code>motor rev</code>, and <code>motor stop</code>.</li><li>Lift the vehicle, send <code>drive on</code>, use CH0/CH2 for limited low-speed RC testing, then send <code>drive off</code>.</li></ol>',7)),n(t,{locale:"en"})])}const w=r(s,[["render",l]]);export{g as __pageData,w as default};
